import React from "react";
import { Link, useLocation } from "react-router-dom";
import "./Confirmation.css";

function Confirmation() {
  const location = useLocation();
  const orderId = location.state?.orderId || Math.floor(Math.random() * 100000);

  return (
    <div className="confirmation-container">
      <h2>🎉 Merci pour votre achat !</h2>
      <p>
        Votre paiement a été confirmé avec succès.  
        Numéro de commande : <strong>#{orderId}</strong>
      </p>
      <p>
        Vous recevrez bientôt un email de confirmation de PayPal avec les détails
        de votre transaction.
      </p>

      <Link to="/gallery">
        <button className="back-btn">Retour à la galerie</button>
      </Link>
    </div>
  );
}

export default Confirmation;
